package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.nio.file.{Files, Path, Paths}
import java.nio.charset.StandardCharsets

@Singleton
class UserFilesController @Inject() (cc: ControllerComponents) extends AbstractController(cc) {

  private val uploadsRoot: Path = Paths.get("uploads").toAbsolutePath.normalize

  def getFile(filename: String): Action[AnyContent] = Action {
    val normalized = filename.replace('\\', '/')
    val requestedPath = uploadsRoot.resolve(normalized).normalize

    if (!requestedPath.startsWith(uploadsRoot)) {
      Forbidden("Invalid path")
    } else if (!Files.exists(requestedPath) || !Files.isRegularFile(requestedPath)) {
      NotFound("File not found")
    } else {
      val src = Source.fromFile(requestedPath.toFile)(StandardCharsets.UTF_8)
      try {
        Ok(src.mkString).as("text/plain; charset=utf-8")
      } finally {
        src.close()
      }
    }
  }
}